func (o *PointSystem) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "PointRules":
		rels, ok := retrieved.(PointRuleSlice)
		if !ok {
			return fmt.Errorf("pointSystem cannot load %T as %q", retrieved, name)
		}

		o.R.PointRules = rels
		o.R.Loaded.PointRules = true

		for _, rel := range rels {
			if rel != nil {
				rel.R.PointSystem = o
				rel.R.Loaded.PointSystem = true
			}
		}
		return nil
	case "Seasons":
		rels, ok := retrieved.(SeasonSlice)
		if !ok {
			return fmt.Errorf("pointSystem cannot load %T as %q", retrieved, name)
		}

		o.R.Seasons = rels
		o.R.Loaded.Seasons = true

		for _, rel := range rels {
			if rel != nil {
				rel.R.PointSystem = o
				rel.R.Loaded.PointSystem = true
			}
		}
		return nil
	default:
		return fmt.Errorf("pointSystem has no relationship %q", name)
	}
}

