// LoadPointRules loads the pointSystem's PointRules into the .R struct
func (o *PointSystem) LoadPointRules(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.PointRules = nil
	o.R.Loaded.PointRules = false

	related, err := o.PointRules(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, rel := range related {
		rel.R.PointSystem = o
		rel.R.Loaded.PointSystem = true
	}

	o.R.PointRules = related
	o.R.Loaded.PointRules = true
	return nil
}

// LoadPointRules loads the pointSystem's PointRules into the .R struct
func (os PointSystemSlice) LoadPointRules(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	pointRules, err := os.PointRules(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		o.R.PointRules = nil
		o.R.Loaded.PointRules = true
	}
	// O(N+M) stitch via a map keyed by the join column (key -> []parent; was O(N*M)).
	pointSystemByKey := make(map[int32][]*PointSystem, len(os))
	for _, o := range os {
		if o == nil {
			continue
		}

		pointSystemByKey[o.ID] = append(pointSystemByKey[o.ID], o)
	}

	for _, rel := range pointRules {

		owners, ok := pointSystemByKey[rel.PointSystemID]
		if !ok {
			continue
		}

		for _, o := range owners {

			rel.R.PointSystem = o
			rel.R.Loaded.PointSystem = true

			o.R.PointRules = append(o.R.PointRules, rel)

		}
	}

	return nil
}

