type pointSystemCountPreloader struct {
	PointRules func(...bob.Mod[*dialect.SelectQuery]) psql.Preloader
	Seasons    func(...bob.Mod[*dialect.SelectQuery]) psql.Preloader
}

func buildPointSystemCountPreloader() pointSystemCountPreloader {
	return pointSystemCountPreloader{
		PointRules: func(mods ...bob.Mod[*dialect.SelectQuery]) psql.Preloader {
			return countPreloader[*PointSystem]("PointRules", func(parent string) bob.Expression {
				// Build a correlated subquery: (SELECT COUNT(*) FROM related WHERE fk = parent.pk)
				if parent == "" {
					parent = PointSystems.Alias()
				}

				subqueryMods := []bob.Mod[*dialect.SelectQuery]{
					sm.Columns(psql.Raw("count(*)")),

					sm.From(PointRules.NameAsExpr()),
					sm.Where(psql.Quote(PointRules.Alias(), "point_system_id").EQ(psql.Quote(parent, "id"))),
				}
				subqueryMods = append(subqueryMods, mods...)
				return psql.Group(psql.Select(subqueryMods...).Expression)
			})
		},
		Seasons: func(mods ...bob.Mod[*dialect.SelectQuery]) psql.Preloader {
			return countPreloader[*PointSystem]("Seasons", func(parent string) bob.Expression {
				// Build a correlated subquery: (SELECT COUNT(*) FROM related WHERE fk = parent.pk)
				if parent == "" {
					parent = PointSystems.Alias()
				}

				subqueryMods := []bob.Mod[*dialect.SelectQuery]{
					sm.Columns(psql.Raw("count(*)")),

					sm.From(Seasons.NameAsExpr()),
					sm.Where(psql.Quote(Seasons.Alias(), "point_system_id").EQ(psql.Quote(parent, "id"))),
				}
				subqueryMods = append(subqueryMods, mods...)
				return psql.Group(psql.Select(subqueryMods...).Expression)
			})
		},
	}
}

